const rows = items.map(i => i.json);

function getRow(rows, rowNum) {
  const r = rows.find(x => x.row_number === rowNum);
  return r ? (r['col_2'] || r['B'] || '') : '';
}

// -- Core config --
const config = {
  apiKey:          String(getRow(rows, 4)),
  assistantId:     String(getRow(rows, 5)),
  batchSize:       parseInt(getRow(rows, 6))  || 10,
  maxDuration:     parseInt(getRow(rows, 7))  || 10,
  concurrentCalls: parseInt(getRow(rows, 8))  || 1,
  pollIntervalMin: parseInt(getRow(rows, 9))  || 2,
  maxAttempts:     parseInt(getRow(rows, 10)) || 10,
  maxPerSlot:      parseInt(getRow(rows, 11)) || 2,
};

// -- Caller phone numbers map (rows 25-34) --
// Each row: CONFIGURATION = Label, col_2 = Phone Number, col_3 = Vapi Phone Number ID
// Build: callerPhoneNumbers array + areaCodeMap for matching
const callerPhoneRows = rows.filter(r => r.row_number >= 25 && r.row_number <= 34);
const callerPhoneNumbers = [];
const areaCodeMap = {};

for (const r of callerPhoneRows) {
  const label   = String(r['CONFIGURATION'] || r['A'] || '').trim();
  const phoneNum = String(r['col_2'] || r['B'] || '').trim();
  const vapiId   = String(r['col_3'] || r['C'] || '').trim();
  if (!vapiId || !phoneNum) continue;
  callerPhoneNumbers.push({ label, phoneNumber: phoneNum, vapiPhoneNumberId: vapiId });
  // Extract area code: strip non-digits, skip country code if 11 digits
  const digits = phoneNum.replace(/\D/g, '');
  const areaCode = digits.length === 11 ? digits.substring(1, 4) : digits.substring(0, 3);
  if (areaCode) areaCodeMap[areaCode] = vapiId;
}

// Default fallback = row 12 ("Vapi Phone Number ID") — explicit config value
// Falls back to first in list if row 12 is empty
const defaultPhoneNumberId = String(getRow(rows, 12)).trim() ||
  (callerPhoneNumbers.length > 0 ? callerPhoneNumbers[0].vapiPhoneNumberId : '');

// -- Time slot logic (Eastern Time) --
const now = new Date();
const etStr = now.toLocaleString('en-US', { timeZone: 'America/New_York' });
const etHour = new Date(etStr).getHours();

const slots = [
  { name: '8am-10am',  startHour: 8,  endHour: 10, col: 'D' },
  { name: '10am-12pm', startHour: 10, endHour: 12, col: 'E' },
  { name: '12pm-2pm',  startHour: 12, endHour: 14, col: 'F' },
  { name: '2pm-4pm',   startHour: 14, endHour: 16, col: 'G' },
  { name: '4pm-6pm',   startHour: 16, endHour: 18, col: 'H' },
];

const currentSlot = slots.find(s => etHour >= s.startHour && etHour < s.endHour) || null;

const etDate = new Date(etStr);
const todayDateStr = etDate.getFullYear() + '-' +
  String(etDate.getMonth() + 1).padStart(2, '0') + '-' +
  String(etDate.getDate()).padStart(2, '0');

return [{
  json: {
    config,
    callerPhoneNumbers,
    areaCodeMap,
    defaultPhoneNumberId,
    currentSlot,
    todayDateStr,
    etHour,
    withinHours: currentSlot !== null
  }
}];

// Input 0 = Read ManyMangos Pick  (has 'Mobile Phone Number' + 'Contact ID')
// Input 1 = Read Numbers Sheet     (has 'Phone Number')
// Read by input index to avoid misclassification by column names

const pickItems   = $input.all(0).map(i => i.json);
const numberItems = $input.all(1).map(i => i.json);

// Normalise: strip spaces, dashes, dots, parens, plus signs
function normalise(p) {
  return String(p || '').trim().replace(/[\s\-().+]/g, '');
}

// Build set of existing phone numbers from the Numbers sheet
const existingNumbers = new Set(
  numberItems
    .map(r => normalise(r['Phone Number']))
    .filter(Boolean)
);

// Find pick contacts whose mobile number isn't already in the Numbers sheet
const seen = new Set();
const newContacts = pickItems.filter(r => {
  const phone = normalise(r['Mobile Phone Number']);
  if (!phone) return false;
  if (existingNumbers.has(phone)) return false;  // already tracked
  if (seen.has(phone)) return false;             // deduplicate within pick list
  seen.add(phone);
  return true;
});

return [{ json: { newContacts, newCount: newContacts.length } }];

const configData = $('Extract Config Values').first().json;
let { config, currentSlot, todayDateStr } = configData;

if (!currentSlot) {
  // Outside calling hours — use first slot as fallback so testing works at any time
  currentSlot = { name: '8am-10am', startHour: 8, endHour: 10, col: 'D' };
}

const slotColMap = {
  'D': '8am-10am',
  'E': '10am-12pm',
  'F': '12pm-2pm',
  'G': '2pm-4pm',
  'H': '4pm-6pm'
};

const slotHeader = slotColMap[currentSlot.col];

const allRows = items.map((item, idx) => ({
  ...item.json,
  _rowIndex: idx + 2
}));

const eligible = [];

const skipped = {
  done: 0,
  calledToday: 0,
  maxAttempts: 0,
  slotFull: 0,
  inProgress: 0
};

for (const row of allRows) {

  const phone = String(row['Phone Number'] || '').trim();

  if (!phone) continue;

  const status = String(row['Status'] || '').trim();
  const totalAttempts = parseInt(row['Total Attempts']) || 0;
  const slotAttempts = parseInt(row[slotHeader]) || 0;
  const lastCalledAt = row['Last Called At'] || '';

  if (['Human Answered', 'Dead', 'Needs Review'].includes(status)) {
    skipped.done++;
    continue;
  }

  if (status === 'In Progress') {
    skipped.inProgress++;
    continue;
  }

  if (lastCalledAt) {
    const lastDate = new Date(lastCalledAt);

    const lastET = new Date(
      lastDate.toLocaleString('en-US', {
        timeZone: 'America/New_York'
      })
    );

    const lastStr =
      lastET.getFullYear() + '-' +
      String(lastET.getMonth() + 1).padStart(2, '0') + '-' +
      String(lastET.getDate()).padStart(2, '0');

    if (lastStr === todayDateStr) {
      skipped.calledToday++;
      continue;
    }
  }

  if (totalAttempts >= config.maxAttempts) {
    skipped.maxAttempts++;
    continue;
  }

  if (slotAttempts >= config.maxPerSlot) {
    skipped.slotFull++;
    continue;
  }

  if (!['Pending', 'Retry', ''].includes(status)) {
    continue;
  }

  if (eligible.length < config.batchSize) {

    // Ensure E.164 format: add + if missing
    const e164Phone = phone.startsWith('+')
      ? phone
      : '+' + phone;

    eligible.push({
      phone_number: e164Phone,
      _rowIndex: row._rowIndex,
      _totalAttempts: totalAttempts,
      _slotAttempts: slotAttempts,
      _slotHeader: slotHeader
    });
  }
}

// Always use default phone number ID
const defaultPhoneNumberId = configData.defaultPhoneNumberId || '';

eligible.forEach(e => {
  e.callerPhoneNumberId = defaultPhoneNumberId;
});

return [{
  json: {
    eligible,
    skipped,
    currentSlot,
    config,
    todayDateStr,
    hasEligible: eligible.length > 0
  }
}];









