const existingItems = $('Read Numbers Sheet').all();
const existingData = existingItems.map(i => i.json);

// If incoming items have Phone Number they are newly appended contacts (true branch)
// Otherwise it's the pass-through from the If false branch
const incomingItems = items.map(i => i.json);
const hasNewData = incomingItems.some(i => i['Phone Number'] || i['phoneNumber']);

const merged = hasNewData
  ? [...existingData, ...incomingItems]
  : existingData;

return merged.map(d => ({ json: d }));

// Each item is one call response from POST /call
// $input.item has the Vapi call response, Loop Over Calls context has the original lead data

const callResponse = $input.first().json;
const callId = callResponse.id;
const leadData = $('Loop Over Calls').first().json; // current loop item (the prepared lead)
const currentSlot = leadData.currentSlot;
const now = new Date().toISOString();

if (!callId) {
  throw new Error('No call ID returned from Vapi: ' + JSON.stringify(callResponse));
}

// Remove leading +
const cleanPhone = String(leadData.phone_number || '').replace(/^\+/, '');

return [{
  json: {
    'Phone Number':   cleanPhone,
    phone:            cleanPhone,
    callId,
    currentSlotName:  currentSlot.name,
    newTotalAttempts: (leadData._totalAttempts || 0) + 1,
    now,
    Status:           'In Progress',

    '8am-10am':  currentSlot.col === 'D' ? (leadData._slotAttempts || 0) + 1 : '',
    '10am-12pm': currentSlot.col === 'E' ? (leadData._slotAttempts || 0) + 1 : '',
    '12pm-2pm':  currentSlot.col === 'F' ? (leadData._slotAttempts || 0) + 1 : '',
    '2pm-4pm':   currentSlot.col === 'G' ? (leadData._slotAttempts || 0) + 1 : '',
    '4pm-6pm':   currentSlot.col === 'H' ? (leadData._slotAttempts || 0) + 1 : '',

    'Total Attempts': (leadData._totalAttempts || 0) + 1,
    'Last Call ID':   callId,
    'Last Called At': now,

    _rowIndex:       leadData._rowIndex,
    _totalAttempts:  (leadData._totalAttempts || 0) + 1,
    _slotAttempts:   leadData._slotAttempts,
    _slotHeader:     leadData._slotHeader
  }
}];

// Input: full Vapi GET /call response (Poll Completed? TRUE branch)
// Extracts all fields + classifies the call outcome

return items.map(item => {
  const call = item.json;

  // --- Duration (seconds) ---
  let duration = 0;
  if (call.startedAt && call.endedAt) {
    duration = Math.round(
      (new Date(call.endedAt) - new Date(call.startedAt)) / 1000
    );
  }

  // --- Phone number (strip leading +) ---
  const phone = String(
    call.customer?.number ||
    call.artifact?.variables?.customer?.number ||
    ''
  ).replace(/^\+/, '');

  // --- Transcript ---
  const transcriptText =
    call.transcript ||
    call.artifact?.transcript ||
    '';

  // --- Recording URLs ---
  const recordingUrl =
    call.recordingUrl ||
    call.artifact?.recordingUrl ||
    call.artifact?.recording?.mono?.combinedUrl ||
    '';

  const stereoRecordingUrl =
    call.stereoRecordingUrl ||
    call.artifact?.stereoRecordingUrl ||
    call.artifact?.recording?.stereoUrl ||
    '';

  // --- Vapi analysis ---
  const endedReason       = call.endedReason || '';
  const status            = call.status || '';
  const summary           = call.analysis?.summary || call.summary || '';
  const successEvaluation = call.analysis?.successEvaluation ?? null;
  const cost              = call.cost ?? call.costBreakdown?.total ?? '';

  // --- IDs + timestamps ---
  const callId            = call.id || '';
  const assistantId       = call.assistantId || '';
  const phoneNumberId     = call.phoneNumberId || '';
  const phoneCallProvider = call.phoneCallProvider || '';
  const startedAt         = call.startedAt || '';
  const endedAt           = call.endedAt   || '';
  const createdAt         = call.createdAt || '';

  // --- Assistant name ---
  const assistantName =
    call.artifact?.assistantActivations?.[0]?.assistantName || '';

  // --- Clean message list (skip system) ---
  const rawMessages = call.artifact?.messages || call.messages || [];
  const messages = rawMessages
    .filter(m => m.role !== 'system')
    .map(m => ({
      role:             m.role === 'bot' ? 'assistant' : m.role,
      message:          m.message || '',
      secondsFromStart: m.secondsFromStart ?? null
    }));

  // --- Lead context ---
  // Mark Numbers In Progress stored _totalAttempts AFTER incrementing (+1 was applied there)
  // so newTotalAttempts is already the count for THIS call
  const leadContext    = $('Mark Numbers In Progress').first()?.json ?? {};
  const _rowIndex      = leadContext._rowIndex      ?? null;
  // newTotalAttempts = attempts including this call; _totalAttempts is same value post-increment
  const totalAttempts  = leadContext._totalAttempts ?? leadContext.newTotalAttempts ?? 1;
  const _slotAttempts  = leadContext._slotAttempts  ?? 0;
  const _slotHeader    = leadContext._slotHeader    ?? '';
  const maxAttempts    = $('Extract Config Values').first().json.config?.maxAttempts ?? 10;

  // =========================================================================
  // CLASSIFICATION
  // Categories: Human Answered | Voicemail | IVR/Call Screening | No Answer
  // =========================================================================

  const transcriptLower = transcriptText.toLowerCase();
  const reason          = endedReason.toLowerCase();

  // Did a real human user actually speak?
  const userMessages = rawMessages.filter(m => m.role === 'user');
  const userSpoke    = userMessages.length > 0;

  // 1. Explicit Vapi voicemail signal
  const isVapiVoicemail = reason === 'voicemail';

  // 2. Voicemail transcript patterns
  const voicemailPhrases = [
    'please leave a message',
    'leave a message after the tone',
    'leave a message after the beep',
    'your call has been forwarded to an automated voice',
    'no one is available',
    'mailbox is full',
    'record your message',
    'record a message',
    'at the tone',
    'press 1 to leave a message',
    'voicemail',
    'voice mail',
  ];
  const hasVoicemailPhrase = voicemailPhrases.some(p => transcriptLower.includes(p));

  // 3. IVR / Call Screening transcript patterns
  const ivrPhrases = [
    'press 1',
    'press 2',
    'press 3',
    'for english press',
    'para espa\u00f1ol',
    'please hold',
    'your call is important',
    'all agents are busy',
    'wait time is approximately',
    'thank you for calling',
    'for hours and location',
    'to repeat this menu',
    'to speak with a representative',
    'to leave a message',
    'is not available',
    'not in service',
    'number you have dialed',
    'the number you are trying to reach',
    'this number has been disconnected',
  ];
  const callScreeningPhrases = [
    'who is calling',
    'who may i say is calling',
    'may i ask who is calling',
    'can i ask who is calling',
    'please state your name',
    'what is this regarding',
    'hold while i connect',
    'screening',
  ];
  const hasIvrPhrase       = ivrPhrases.some(p => transcriptLower.includes(p));
  const hasScreeningPhrase = callScreeningPhrases.some(p => transcriptLower.includes(p));

  // 4. No-answer Vapi reasons
  const noAnswerReasons = [
    'no-answer',
    'customer-did-not-answer',
    'customer-busy',
    'line-busy',
    'busy',
    'failed',
    'call-error',
  ];
  const isNoAnswerReason = noAnswerReasons.some(r => reason.includes(r));

  // 5. Human-answered Vapi reasons
  const humanAnswerReasons = [
    'customer-ended-call',
    'assistant-ended-call',
    'assistant-said-end-call-phrase',
    'call-completed',
  ];
  const isHumanReason = humanAnswerReasons.some(r => reason.includes(r));

  // 6. Short-call heuristic: under 8s, no user speech = no-answer/IVR intercept
  const isVeryShortNoSpeech = duration < 8 && !userSpoke;

  // DECISION TREE
  let classification;

  if (isVapiVoicemail || hasVoicemailPhrase) {
    // Voicemail signal takes priority; only override if clear human end + user spoke + NOT vapi voicemail
    if (isHumanReason && userSpoke && !isVapiVoicemail) {
      classification = 'Human Answered';
    } else {
      classification = 'Voicemail';
    }
  } else if (hasScreeningPhrase) {
    classification = 'IVR/Call Screening';
  } else if (hasIvrPhrase && !userSpoke) {
    classification = 'IVR/Call Screening';
  } else if (hasIvrPhrase && userSpoke && reason === 'exceeded-max-duration') {
    classification = 'IVR/Call Screening';
  } else if (isHumanReason && userSpoke) {
    classification = 'Human Answered';
  } else if (isHumanReason && !userSpoke && duration > 15) {
    classification = 'Human Answered';
  } else if (isNoAnswerReason || isVeryShortNoSpeech) {
    classification = 'No Answer';
  } else if (reason === 'exceeded-max-duration' && !userSpoke) {
    classification = 'IVR/Call Screening';
  } else if (reason === 'exceeded-max-duration' && userSpoke) {
    classification = 'Human Answered';
  } else if (userSpoke) {
    classification = 'Human Answered';
  } else {
    classification = 'No Answer';
  }

  return {
    json: {
      callId,
      assistantId,
      assistantName,
      phoneNumberId,
      phoneCallProvider,
      phone,
      status,
      endedReason,
      duration,
      startedAt,
      endedAt,
      createdAt,
      transcriptText,
      summary,
      successEvaluation,
      messages,
      recordingUrl,
      stereoRecordingUrl,
      cost,
      classification,
      _rowIndex,
      totalAttempts,
      _slotAttempts,
      _slotHeader,
      maxAttempts
    }
  };
});

const configData = $('Extract Config Values').first().json;
const { config, areaCodeMap, defaultPhoneNumberId } = configData;
const { eligible, currentSlot } = $('Filter Eligible Numbers').first().json;

// Area code match: strip non-digits, skip country code if 11 digits
function getPhoneNumberId(phone) {
  const digits = String(phone).replace(/\D/g, '');
  const areaCode = digits.length === 11 ? digits.substring(1, 4) : digits.substring(0, 3);
  return areaCodeMap[areaCode] || defaultPhoneNumberId;
}

// Ensure E.164 format
function toE164(phone) {
  const s = String(phone).trim();
  return s.startsWith('+') ? s : '+' + s;
}

return eligible.map(e => ({
  json: {
    phone_number:   toE164(e.phone_number),
    phoneNumberId:  getPhoneNumberId(e.phone_number),
    assistantId:    config.assistantId,
    apiKey:         config.apiKey,
    maxDuration:    config.maxDuration,
    _rowIndex:      e._rowIndex,
    _totalAttempts: e._totalAttempts,
    _slotAttempts:  e._slotAttempts,
    _slotHeader:    e._slotHeader,
    currentSlot
  }
}));

// Input: output of Format conversation details
// Builds the final sheet-ready payload for Numbers tab + Call Log tab

const formatted   = $('Format conversation details').item.json;
const currentSlot = $('Filter Eligible Numbers').first().json.currentSlot;
const now         = new Date().toISOString();

const classification = formatted.classification;  // Human Answered | Voicemail | IVR/Call Screening | No Answer
const totalAttempts  = formatted.totalAttempts;   // already incremented (+1) by Mark Numbers In Progress
const maxAttempts    = formatted.maxAttempts;
const slotName       = currentSlot ? currentSlot.name : '8am-10am';
const slotCol        = currentSlot ? currentSlot.col  : 'D';
const phone          = formatted.phone ? (formatted.phone.startsWith('+') ? formatted.phone : '+' + formatted.phone) : '';
const isHuman        = classification === 'Human Answered';

// --- Final Status ---
// Human Answered    -> stop, mark done
// IVR/Call Screening -> Dead (not a real person, don't waste more attempts)
// Voicemail          -> Retry until maxAttempts, then Dead
// No Answer          -> Retry until maxAttempts, then Dead
let finalStatus;
if (isHuman) {
  finalStatus = 'Human Answered';
} else if (classification === 'IVR/Call Screening') {
  finalStatus = 'Dead';
} else if (totalAttempts >= maxAttempts) {
  finalStatus = 'Dead';
} else {
  finalStatus = 'Retry';
}

// --- Slot attempt columns (only the active slot gets a value) ---
const slot8to10  = slotCol === 'D' ? totalAttempts : '';
const slot10to12 = slotCol === 'E' ? totalAttempts : '';
const slot12to2  = slotCol === 'F' ? totalAttempts : '';
const slot2to4   = slotCol === 'G' ? totalAttempts : '';
const slot4to6   = slotCol === 'H' ? totalAttempts : '';

return {
  json: {
    // Numbers sheet columns
    'Phone Number':        phone,
    'Status':              finalStatus,
    'Answered In Slot':    isHuman ? slotName : '',
    '8am-10am':            slot8to10,
    '10am-12pm':           slot10to12,
    '12pm-2pm':            slot12to2,
    '2pm-4pm':             slot2to4,
    '4pm-6pm':             slot4to6,
    'Total Attempts':      totalAttempts,
    'Last Call ID':        formatted.callId,
    'Last Duration (s)':   formatted.duration,
    'Last Transcript':     formatted.transcriptText,
    'Last Classification': classification,
    'Last Called At':      formatted.startedAt || now,
    'Recording URL':       formatted.recordingUrl,
    'Answered At':         isHuman ? now : '',

    // Call Log sheet columns
    phone,
    batchId:          '',
    currentSlotName:  slotName,
    newTotalAttempts: totalAttempts,
    now,

    // Pass-through for downstream
    classification,
    finalStatus,
    isHuman,
    slotName,
    totalAttempts,
    recordingUrl:  formatted.recordingUrl,
    endedReason:   formatted.endedReason,
    duration:      formatted.duration,
    transcript:    formatted.transcriptText
  }
};
